const amqplib = require('amqplib');
const { parse } = require('json2csv');

// Connect to RabbitMQ
async function connectToRabbitMQ() {
  const connection = await amqplib.connect('amqp://localhost');
  return connection;
}

// Consume messages from a queue
async function consumeMessages(queueName) {
  const connection = await connectToRabbitMQ();
  const channel = await connection.createChannel();
  const queue = await channel.assertQueue(queueName, { durable: true });
  return channel.consume(queue.queue, (message) => {
    console.log(`Received message: ${message.content}`);
    // Parse JSON messages and use message data to construct database queries or system commands
    const parsedMessage = parse(message.content);
    if (parsedMessage.type === 'database_query') {
      // Execute database query based on message payload
      const query = `SELECT * FROM ${parsedMessage.table} WHERE id = ${parsedMessage.id}`;
      const result = await channel.sendToQueue(queueName, new Buffer(query));
      console.log(`Query executed: ${result}`);
    } else if (parsedMessage.type === 'system_command') {
      // Execute system command based on message payload
      const command = `echo "${parsedMessage.message}" | sudo tee /dev/tty1`;
      const result = await channel.sendToQueue(queueName, new Buffer(command));
      console.log(`Command executed: ${result}`);
    } else {
      // Unknown message type, ignore
      console.log(`Unknown message type: ${parsedMessage.type}`);
    }
  });
}

